import React from 'react'
import {useState} from 'react'

function App(e) {
  const[text, setText] = useState("");
  function liveText(e)
  {
    setText(e.target.value);
  }
  return (
    <>
    <h3>-- Live Preview --</h3>
    <input type="text" placeholder="Enter your text.." onChange={liveText}></input> <br /><br />
    <p>You typed: {text}</p>

    </>
  )
}

export default App